using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Existing documents use "Discriminator", so keep the old property name.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: id format changed from "Blog|1" to just "1".
            // Existing documents use "Blog|{key}" format, so keep the old format.
            entity.HasId(b => new { Discriminator = "Blog", b.Id });

            // Breaking change 3: HasIndex now throws for Cosmos (was silently ignored in EF 8).
            // REMOVED: entity.HasIndex(b => b.Name);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

